import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useMemo, useState } from 'react';
import { Linking, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import OwnerBottomNav from '../components/OwnerBottomNav';
import {
  formatCurrency,
  formatOrderDate,
  formatOrderNumber,
  ORDER_STATUS_META,
  OWNER_STATUS_GROUPS
} from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { fetchOwnerOrders, OrderRecord, OrderStatus, updateOrderStatus } from '../services/firebaseService';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'OwnerOrders'>;

const ownerNextStatus: Partial<Record<OrderStatus, OrderStatus>> = {
  pending: 'confirmed',
  confirmed: 'preparing',
  preparing: 'out_for_delivery',
  out_for_delivery: 'delivered'
};

const actionLabel: Partial<Record<OrderStatus, string>> = {
  pending: 'Confirm Order',
  confirmed: 'Mark Preparing',
  preparing: 'Mark Out for Delivery',
  out_for_delivery: 'Mark Delivered'
};

const OwnerOrdersScreen = () => {
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [selectedStatus, setSelectedStatus] = useState<OrderStatus>('pending');

  const loadOrders = useCallback(async () => {
    const data = await fetchOwnerOrders().catch(() => []);
    setOrders(data);
  }, []);

  useFocusEffect(
    useCallback(() => {
      loadOrders();
    }, [loadOrders])
  );

  const filteredOrders = useMemo(
    () => orders.filter((order) => order.status === selectedStatus),
    [orders, selectedStatus]
  );

  const counts = useMemo(() => {
    return OWNER_STATUS_GROUPS.reduce<Record<OrderStatus, number>>((acc, group) => {
      acc[group.key] = orders.filter((order) => order.status === group.key).length;
      return acc;
    }, {
      pending: 0,
      confirmed: 0,
      preparing: 0,
      out_for_delivery: 0,
      delivered: 0,
      cancelled: 0
    });
  }, [orders]);

  const handleStatusUpdate = async (order: OrderRecord) => {
    const next = ownerNextStatus[order.status];
    if (!next) {
      return;
    }
    await updateOrderStatus(order.id!, next);
    loadOrders();
  };

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <Text style={styles.title}>Owner Order Management</Text>
        <Text style={styles.subtitle}>Review orders by stage, contact customers, and update delivery progress.</Text>

        <View style={styles.statusTabs}>
          {OWNER_STATUS_GROUPS.map((group) => {
            const selected = group.key === selectedStatus;
            return (
              <Pressable
                key={group.key}
                style={[styles.statusTab, selected && styles.statusTabSelected]}
                onPress={() => setSelectedStatus(group.key)}
              >
                <Text style={[styles.statusTabText, selected && styles.statusTabTextSelected]}>{group.label}</Text>
                <Text style={[styles.statusCount, selected && styles.statusCountSelected]}>{counts[group.key]}</Text>
              </Pressable>
            );
          })}
        </View>

        {filteredOrders.length ? (
          filteredOrders.map((order) => {
            const meta = ORDER_STATUS_META[order.status];
            const next = ownerNextStatus[order.status];
            return (
              <View key={order.id} style={styles.orderCard}>
                <View style={styles.orderHeader}>
                  <View>
                    <Text style={styles.orderNumber}>{formatOrderNumber(order)}</Text>
                    <Text style={styles.orderTime}>{formatOrderDate(order.createdAt)}</Text>
                  </View>
                  <View style={[styles.orderStatusPill, { backgroundColor: meta.background }]}>
                    <Text style={[styles.orderStatusText, { color: meta.text }]}>{meta.label}</Text>
                  </View>
                </View>

                <Text style={styles.customerName}>{order.customerName}</Text>
                <Text style={styles.orderInfo}>{order.phone}</Text>
                <Text style={styles.orderInfo}>{order.address}</Text>

                <View style={styles.infoRow}>
                  <View style={styles.infoCell}>
                    <Text style={styles.infoLabel}>Quantity</Text>
                    <Text style={styles.infoValue}>{order.quantity} cans</Text>
                  </View>
                  <View style={styles.infoCell}>
                    <Text style={styles.infoLabel}>Amount</Text>
                    <Text style={styles.infoValue}>{formatCurrency(order.totalAmount)}</Text>
                  </View>
                </View>

                <View style={styles.infoRow}>
                  <View style={styles.infoCell}>
                    <Text style={styles.infoLabel}>Payment type</Text>
                    <Text style={styles.infoValue}>{order.paymentMethod}</Text>
                  </View>
                  <View style={styles.infoCell}>
                    <Text style={styles.infoLabel}>Delivery slot</Text>
                    <Text style={styles.infoValue}>{order.deliverySlot}</Text>
                  </View>
                </View>

                <View style={styles.actionRow}>
                  {next ? (
                    <Pressable style={styles.primaryButton} onPress={() => handleStatusUpdate(order)}>
                      <Text style={styles.primaryButtonText}>{actionLabel[order.status]}</Text>
                    </Pressable>
                  ) : null}
                  <Pressable style={styles.secondaryButton} onPress={() => Linking.openURL(`tel:${order.phone}`)}>
                    <Text style={styles.secondaryButtonText}>Call Customer</Text>
                  </Pressable>
                  <Pressable
                    style={styles.secondaryButton}
                    onPress={() => navigation.navigate('OrderDetails', { orderId: order.id! })}
                  >
                    <Text style={styles.secondaryButtonText}>View Full Details</Text>
                  </Pressable>
                </View>
              </View>
            );
          })
        ) : (
          <View style={styles.emptyCard}>
            <Text style={styles.emptyTitle}>No orders in this stage</Text>
            <Text style={styles.emptyText}>New customer bookings will appear here automatically.</Text>
          </View>
        )}
      </ScrollView>
      <OwnerBottomNav active="OwnerOrders" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF'
  },
  content: {
    padding: 18,
    paddingBottom: 120
  },
  title: {
    color: '#10324A',
    fontSize: 28,
    fontWeight: '900'
  },
  subtitle: {
    marginTop: 8,
    color: '#5E788C',
    fontSize: 14,
    lineHeight: 21
  },
  statusTabs: {
    marginTop: 18,
    gap: 10
  },
  statusTab: {
    backgroundColor: 'white',
    borderRadius: 22,
    padding: 16,
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  statusTabSelected: {
    backgroundColor: '#0D8DD8'
  },
  statusTabText: {
    color: '#10324A',
    fontSize: 15,
    fontWeight: '800'
  },
  statusTabTextSelected: {
    color: 'white'
  },
  statusCount: {
    minWidth: 34,
    textAlign: 'center',
    borderRadius: 999,
    backgroundColor: '#EAF7FF',
    color: '#0D63A8',
    overflow: 'hidden',
    paddingVertical: 6,
    fontSize: 12,
    fontWeight: '800'
  },
  statusCountSelected: {
    backgroundColor: 'rgba(255,255,255,0.2)',
    color: 'white'
  },
  orderCard: {
    marginTop: 16,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  orderHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-start'
  },
  orderNumber: {
    color: '#10324A',
    fontSize: 18,
    fontWeight: '900'
  },
  orderTime: {
    marginTop: 5,
    color: '#6D8699',
    fontSize: 12
  },
  orderStatusPill: {
    borderRadius: 999,
    paddingHorizontal: 12,
    paddingVertical: 8
  },
  orderStatusText: {
    fontSize: 11,
    fontWeight: '800'
  },
  customerName: {
    marginTop: 14,
    color: '#10324A',
    fontSize: 18,
    fontWeight: '800'
  },
  orderInfo: {
    marginTop: 6,
    color: '#5E788C',
    fontSize: 14,
    lineHeight: 20
  },
  infoRow: {
    marginTop: 14,
    flexDirection: 'row',
    gap: 10
  },
  infoCell: {
    flex: 1,
    borderRadius: 18,
    backgroundColor: '#F6FBFF',
    padding: 12
  },
  infoLabel: {
    color: '#6D8699',
    fontSize: 11,
    fontWeight: '700'
  },
  infoValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 14,
    fontWeight: '800'
  },
  actionRow: {
    marginTop: 16,
    gap: 10
  },
  primaryButton: {
    backgroundColor: '#0D8DD8',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: 'white',
    fontSize: 15,
    fontWeight: '900'
  },
  secondaryButton: {
    backgroundColor: '#EAF7FF',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  secondaryButtonText: {
    color: '#0D63A8',
    fontSize: 15,
    fontWeight: '800'
  },
  emptyCard: {
    marginTop: 16,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 20
  },
  emptyTitle: {
    color: '#10324A',
    fontSize: 20,
    fontWeight: '800'
  },
  emptyText: {
    marginTop: 8,
    color: '#6D8699',
    fontSize: 14,
    lineHeight: 21
  }
});

export default OwnerOrdersScreen;
